---
Example (t_array_map.sv):
```
// From IEEE 1800-2023 Section 7.12.5
module t;
  int A[] = '{1,2,3}, B[] = '{2,3,5}, C[$];
  bit Compare[];

  initial begin
    // Form 1: map with implicit iterator 'item'
    A = A.map() with (item + 1'b1);
    // A should be {2,3,4}

    // Form 2: map with named iterator and index
    C = A.map(a) with (a + B[a.index]);
    // C should be {4,6,9}

    // Form 3: element-wise comparison producing bit array
    Compare = A.map(a) with (a == B[a.index]);
    // Compare should be {1,1,0}

    if (A[0] !== 2 || A[1] !== 3 || A[2] !== 4) $stop;
    if (C[0] !== 4 || C[1] !== 6 || C[2] !== 9) $stop;
    if (Compare[0] !== 1'b1 || Compare[1] !== 1'b1 || Compare[2] !== 1'b0) $stop;
    $write("*-* All Finished *-*\n");
    $finish;
  end
endmodule
```

